type CompileStatus = 'idle' | 'compiling' | 'success' | 'error';

// ---------------------------------------------------------------------------
// Preview composition — colored rectangle wrapped by the effect component
// ---------------------------------------------------------------------------

const PREVIEW_FPS = 30;
const PREVIEW_SIZE = 320;

interface PreviewParams {
  durationSeconds: number;
  effectSeconds: number;
  intensity: number;
}

const DEFAULT_PREVIEW_PARAMS: PreviewParams = {
  durationSeconds: 3,
  effectSeconds: 0.7,
  intensity: 0.5,
};

function PreviewRect() {
  return (
    <AbsoluteFill
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #6366f1 0%, #8b5cf6 50%, #a78bfa 100%)',
      }}
    >
      <div
        style={{
          width: '60%',
          height: '60%',
          borderRadius: 16,
          background: 'rgba(255,255,255,0.15)',
          backdropFilter: 'blur(8px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: '#fff',
          fontSize: 24,
          fontWeight: 600,
          letterSpacing: 1,
        }}
      >
        Effect Preview
      </div>
    </AbsoluteFill>
  );
}

function makePreviewComposition(
  EffectComponent: FC<EffectComponentProps> | null,
  params: PreviewParams,
) {
  const durationInFrames = Math.max(1, Math.round(params.durationSeconds * PREVIEW_FPS));
  const effectFrames = Math.max(1, Math.round(params.effectSeconds * PREVIEW_FPS));
  return function EffectPreviewComposition() {
    if (!EffectComponent) {
      return <PreviewRect />;
    }
    return (
      <EffectComponent durationInFrames={durationInFrames} effectFrames={effectFrames} intensity={params.intensity}>
        <PreviewRect />
      </EffectComponent>
    );
  };
}

