export function buildGenerateEffectMessages(input: BuildGenerateEffectMessagesInput): {
  systemMsg: string;
  userMsg: string;
} {
  const { prompt, name, category, existingCode } = input;
  const modeInstructions = existingCode?.trim()
    ? `Edit mode:
