                />
              </div>
              <div className="grid gap-3 sm:grid-cols-3">
                <div className="space-y-1">
                  <label className="text-[10px] text-muted-foreground">Duration: {previewParams.durationSeconds.toFixed(1)}s</label>
                  <Slider
