 61	    if (isModelError && params.model !== GROQ_FALLBACK_MODEL) {
 62	      logger.info(`[AI-GENERATE-EFFECT] Primary model failed (${msg}), falling back to ${GROQ_FALLBACK_MODEL}`);
 63	      return await groq.chat.completions.create({
 64	        ...params,
 65	        model: GROQ_FALLBACK_MODEL,
 66	      } as Parameters<typeof groq.chat.completions.create>[0]);
